metadata = {
    'apiLevel': '2.8',
    'protocolName': 'illuminaIndexPlates_setEonly',
    'author': 'Rachel Voyt',
    'description': '''This protocol is a modified version of the 'Custom CSV Transfer' protocol from OT2, with an added mix step prior to each index primer transfer (only for the first time that index is transferred).'''
}

def run(protocol):

    [pipette_type,
     pipette_mount,
     tip_type,
     tip_reuse,
     transfer_csv] = get_values(  # noqa: F821
        "pipette_type",
        "pipette_mount",
        "tip_type",
        "tip_reuse",
        "transfer_csv")

    # strip headers
    transfer_info = [[val.strip().lower() for val in line.split(',')]
                     for line in transfer_csv.splitlines()
                     if line.split(',')[0].strip()][1:]
    
    # load labware
    for line in transfer_info:
        s_lw, s_slot, d_lw, d_slot = line[2:4] + line[6:8]
        for slot, lw in zip([s_slot, d_slot], [s_lw, d_lw]):
            if not int(slot) in protocol.loaded_labwares:
                protocol.load_labware(lw.lower(), slot)

    # load tipracks
    tipracks = [protocol.load_labware(tip_type, slot)
            for slot in ['4', '7']]

    # load pipettes
    s20 = protocol.load_instrument(pipette_type, pipette_mount, tip_racks=tipracks)
            
    tip_count = 0
    tip_max = len(tipracks*96)

    def pick_up():
        nonlocal tip_count
        if tip_count == tip_max:
            protocol.pause('Please refill tipracks before resuming.')
            s20.reset_tipracks()
            tip_count = 0
        s20.pick_up_tip()
        tip_count += 1

    def parse_well(well):
        letter = well[0]
        number = well[1:]
        return letter.upper() + str(int(number))
    
    source_well_transferred = {}
    def is_first_transfer(source_well):
        if source_well not in source_well_transferred:
            source_well_transferred[source_well] = False
            return True
        return False

    # transfers
    if tip_reuse == 'never':
        pick_up()
    for line in transfer_info:
        _, _, _, s_slot, s_well, h, _, d_slot, d_well, vol = line[:10]
        source = protocol.loaded_labwares[
            int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(float(h))
        dest = protocol.loaded_labwares[
            int(d_slot)].wells_by_name()[parse_well(d_well)]
        
        if tip_reuse == 'always':
            pick_up()

        # Check if it's the first transfer from this source well, and if so, mix
        if is_first_transfer(s_well):
            s20.mix(5, 20, source)

        s20.transfer(float(vol),
                    source,
                    dest,
                    new_tip='never')
        if tip_reuse == 'always':
            s20.drop_tip()
    if s20.hw_pipette['has_tip']:
        s20.drop_tip()